from abc import ABC, abstractmethod
from collections.abc import Iterable
from pathlib import Path
from typing import TypeVar

import pandas as pd
from mlflow.artifacts import download_artifacts
from torch.utils.data import ConcatDataset, Dataset


T = TypeVar("T", covariant=True)


class MetaTiledSlides(ConcatDataset[T], ABC):
    """Abstract base class for creating concatenated datasets from slides and tiles generated by the tiler.

    This class provides a factory method to load and concatenate datasets from different
    sources: local storage, preloaded data, or artifacts stored in MLFlow.

    Attributes:
        slides (pd.DataFrame): DataFrame containing slide metadata.
        tiles (pd.DataFrame): DataFrame containing tile metadata.
    """

    def __init__(
        self,
        *,
        paths: Iterable[Path | str] | None = None,
        uris: Iterable[str] | None = None,
        slides_and_tiles: tuple[pd.DataFrame, pd.DataFrame] | None = None,
    ) -> None:
        """Load slides and tiles from MLFlow artifacts.

        Args:
            paths: List of directories to load slides and tiles from. Each
                directory must include two files: `slides.parquet` and tiles.parquet`.
            uris: List of MLFlow artifact URIs pointing to folders containing
                `slides.parquet` and `tiles.parquet`.
            slides_and_tiles: Tuple containing the slides and tiles DataFrames.
        """
        assert (
            paths or uris or slides_and_tiles
        ), "At least one of paths, uris or slides_and_tiles must be provided."

        self.slides, self.tiles = self.load_slides_and_tiles(paths or [], uris or [])

        if slides_and_tiles is not None:
            self.slides = pd.concat((self.slides, slides_and_tiles[0]))
            self.tiles = pd.concat((self.tiles, slides_and_tiles[1]))

        super().__init__(self.generate_datasets())

    @abstractmethod
    def generate_datasets(self) -> Iterable[Dataset[T]]:
        """Factory method to generate datasets from slides and tiles.

        Example:
            ```python
            return (
                SlideTiles(
                    slide_path=slide.path,
                    level=slide.level,
                    tile_extent_x=slide.tile_extent_x,
                    tile_extent_y=slide.tile_extent_y,
                    tiles=self.filter_tiles_by_slide(slide.id),
                )
                for slide in self.slides.itertuples()
            )
            ```
        """

    def filter_tiles_by_slide(self, slide_id: str) -> pd.DataFrame:
        """Returns a DataFrame containing tiles belonging to a specific slide.

        This function filters the `self.tiles` DataFrame to return only the tiles that
        belong to the specified slide. The `self.tiles` DataFrame is expected to have
        a `slide_id` column.

        Args:
            slide_id: The ID of the slide to filter tiles.
        """
        return self.tiles[self.tiles["slide_id"] == slide_id]

    @staticmethod
    def load_slides_and_tiles(
        paths: Iterable[str | Path], uris: Iterable[str]
    ) -> tuple[pd.DataFrame, pd.DataFrame]:
        """Load slides and tiles parquets from local storage and MLFlow artifacts.

        Args:
            paths: List of directories to load slides and tiles from. Each
                directory must include two files: `slides.parquet` and tiles.parquet`.
            uris: List of MLFlow artifact URIs pointing to folders containing
                `slides.parquet` and `tiles.parquet`.

        Raises:
            FileNotFoundError: If the data cannot be loaded from the specified URIs.

        Returns:
            A tuple containing the slides and tiles DataFrames.
        """
        artifacts_paths = [download_artifacts(artifact_uri=uri) for uri in uris]

        slides_dfs: list[pd.DataFrame] = []
        tiles_dfs: list[pd.DataFrame] = []

        for path in (*paths, *artifacts_paths):
            if isinstance(path, str):
                path = Path(path)

            try:
                slides = pd.read_parquet(path / "slides.parquet")
                tiles = pd.read_parquet(path / "tiles.parquet")
            except OSError as e:
                raise FileNotFoundError(f"Cannot load data from {path}.") from e

            slides_dfs.append(slides)
            tiles_dfs.append(tiles)

        return pd.concat(slides_dfs).reset_index(), pd.concat(tiles_dfs).reset_index()
